        List<Future<?>> clearTasks = new ArrayList<>();
        for (int i = 0; i < workerCount; i++) {
            clearTasks.add(workers.submit(ThreadBridge::clear));
        }
        for (Future<?> task : clearTasks) {
            task.get(5, TimeUnit.SECONDS);
        }
        revisions.close();
        workers.shutdownNow();
        workers.awaitTermination(5, TimeUnit.SECONDS);
    }

